import React from 'react';
import './App.css';
import { Link } from 'react-router-dom';  // Link를 사용하여 라우팅

const Modal = ({ isOpen, onClose }) => { 
    if (!isOpen) return null;  

    return (
        <div className='modal'>
            <ul className='modal_1'>
                <li>
                    {/* Link로 새 탭에서 열기 */}
                    <Link to='/diarypage' target='_blank'>
                        잘자요
                    </Link>
                </li>
                <li>
                    애칭 설정 
                </li>
                <li>
                    Diray List
                </li>
            </ul>
            <ul className='modal_2'>
                <li></li>
            </ul> 
        </div>
    );
}

export default Modal;
